(1, 'device_fingerprint', 'Variation des Empreintes', 'Ne jamais utiliser deux fois la même empreinte numérique.', 'Google détecte les motifs répétitifs dans les configurations navigateur et appareil.', 'critical', '💻', '{\"risk_reduction\": \"95%\", \"success_rate\": \"Very High\"}', '[\"Utiliser des User-Agents différents\", \"Varier les résolutions d\'écran\"]', '[\"Toujours le même navigateur\", \"Même version OS\"]', '[\"Utilisez des profils anti-détection\"]', 1, 1, '2026-02-05 16:20:18', '2026-02-05 16:20:18'),
(2, 'ip_rotation', 'Rotation IP Résidentielle', 'Utiliser uniquement des IPs résidentielles françaises de haute qualité.', 'Les IPs de data centers sont immédiatement flaguées par Google.', 'critical', '🌐', '{\"risk_reduction\": \"90%\", \"success_rate\": \"High\"}', '[\"IP mobile 4G/5G\", \"IP résidentielle FAI classique\"]', '[\"VPN gratuit\", \"Proxy datacenter\"]', '[\"Vérifiez le score de fraude IP\"]', 2, 1, '2026-02-05 16:20:18', '2026-02-05 16:20:18'),
(3, 'behavior_mimic', 'Comportement Humain', 'Simuler une navigation naturelle avant de poster.', 'Un humain ne va pas directement sur l\'URL de dépôt d\'avis.', 'high', 'mouse', '{\"risk_reduction\": \"80%\", \"success_rate\": \"High\"}', '[\"Scroller\", \"Lire d\'autres avis\", \"Visiter le site web\"]', '[\"Lien direct dépôt\", \"Copier-coller immédiat\"]', '[\"Restez au moins 2 minutes sur la page\"]', 3, 1, '2026-02-05 16:20:18', '2026-02-05 16:20:18');
