('5ccdef6e-0bfb-44ce-8868-d80e3e86ae01', 'fe333421-373a-4f3e-b39b-14390ea5fc80', 'google ads super', 4, 'Léa M.', 'approved', '2026-01-30 19:26:52', '2026-02-02 08:54:08'),
